import{BaseComponent as a,html as t,define as r}from"../core.min.js";export class DvState extends a{static observedAttributes=["data-state"];initialState(){return{status:this.str("state","empty")}}onAttribute(s,e){s==="data-state"&&(this.state.status=e??"empty")}retry(){this.emit("retry")}template(){return this.state.status==="loading"?t`<p class="dv-state" role="status">${this.str("loading","Loading\u2026")}</p>`:this.state.status==="error"?t`<section class="dv-state" role="alert"><p>${this.str("error","Something went wrong.")}</p><button type="button" data-on:click="retry">${this.str("retry-label","Try again")}</button></section>`:t`<p class="dv-state">${this.str("empty","Nothing to show yet.")}</p>`}}r("dv-state",DvState);
